    with link = "point.de.Heessen-Hp", railway = :station {
        track(hh[:heh - 0.5sw, :heh + 0.5sw]);
        track(:nopax, hh[:heh - 0.5sw, :heh + 0.5sw] >> 2mo);
        marker(:left :de.hp, hh[:heh] << 0.5mo << 0.5mt);
        station(:right :left_align,
            hh[:heh] << 0.5mo << 0.5mt << 1sh + (1.5dt, 1.8dt),
            "Heessen Hp",
            "1700\u{2009}·\u{2009}2990: 172,339"
        );
    }

    with link = "line.de.1700" {
        track(:ror, hh[:heh + 0.49sw, :hee - 0.49sw]);
    }

    # point.de.Heessen  de.2990

    with link = "line.de.1700" {
        with layer = -1 track(:ror, hh[:hee + 0.49sw, :hee.yh]);
        with layer = -1 track(:ror:lor, hh[:hee.yh, :ham.yf]);
    }
}

